mapper.select:
SELECT COUNT(1) FROM exam_paper

    
        AND title LIKE CONCAT('%', #{title}, '%')
    
    
        AND course_id = #{courseId}
    
    
        AND chapter_id = #{chapterId}
    
    
        AND creator_id = #{creatorId}
    
    
        AND status = #{status}

SELECT ep.*, c.course_name as courseName
FROM exam_paper ep
LEFT JOIN course c ON ep.course_id = c.id

    
        AND ep.title LIKE CONCAT('%', #{title}, '%')
    
    
        AND ep.course_id = #{courseId}
    
    
        AND ep.chapter_id = #{chapterId}
    
    
        AND ep.creator_id = #{creatorId}
    
    
        AND ep.status = #{status}
    

ORDER BY ep.create_time DESC
LIMIT #{pageSize} OFFSET #{offset}
